import { useState } from 'react'
import './Testimonials.css'
import { FaChevronLeft, FaChevronRight } from 'react-icons/fa'

const testimonials = [
    {
        img: '/photos/olena.png',
        quote: 'mWallet допоміг мені побачити справжній стан бюджету',
        author: 'Олена, 27 років'
    },
    {
        img: '/photos/olena.png',
        quote: 'Я вперше реально контролюю свої витрати!',
        author: 'Олена, 27 років'
    },
    {
        img: '/photos/olena.png',
        quote: 'mWallet навчив мене інвестувати',
        author: 'Олена, 27 років'
    },
    {
        img: '/photos/olena.png',
        quote: 'Додаток дуже простий і зручний',
        author: 'Олена, 27 років'
    },
    {
        img: '/photos/olena.png',
        quote: 'Вперше відчуваю фінансову впевненість',
        author: 'Олена, 27 років'
    },
    {
        img: '/photos/olena.png',
        quote: 'Найкращий додаток для ведення бюджету!',
        author: 'Олена, 27 років'
    },
]

const Testimonials = () => {
    const [currentIndex, setCurrentIndex] = useState(0)
    const visibleCount = 2

    const handlePrev = () => {
        setCurrentIndex(prev => Math.max(prev - visibleCount, 0))
    }

    const handleNext = () => {
        setCurrentIndex(prev => Math.min(prev + visibleCount, testimonials.length - visibleCount))
    }

    const visibleTestimonials = testimonials.slice(currentIndex, currentIndex + visibleCount)

    return (
        <section className="testimonials" id="testimonials">
            <h2>Що кажуть про нас</h2>

            <div className="testimonial-slider-controls">
                <button className="slider-arrow" onClick={handlePrev} disabled={currentIndex === 0}>
                    <FaChevronLeft />
                </button>

                <div className="testimonials-grid">
                    {visibleTestimonials.map((t, index) => (
                        <div className="testimonial-card" key={index}>
                            <img src={t.img} alt={t.author} className="avatar" />
                            <p className="quote">"{t.quote}"</p>
                            <p className="author">{t.author}</p>
                        </div>
                    ))}
                </div>

                <button
                    className="slider-arrow"
                    onClick={handleNext}
                    disabled={currentIndex + visibleCount >= testimonials.length}
                >
                    <FaChevronRight />
                </button>
            </div>

            <div className="partners">
                <img src="/photos/trustly.png" alt="Trustly logo" />
                <img src="/photos/visa.png" alt="Visa logo" />
                <img src="/photos/gpay.png" alt="Google Pay logo" />
            </div>
        </section>
    )
}

export default Testimonials
